import { Loc } from 'main.core';
import { AirButtonStyle, Button as ToggleButton } from 'ui.vue3.components.button';
import { Outline } from 'ui.icon-set.api.core';
import { mapActions, mapState } from 'ui.vue3.pinia';
import { useNodeDataInspectorStore } from '../../../../shared/stores/node-data-inspector-store';

// @vue/component
export const ToggleInspectorControl = {
	name: 'ToggleInspectorControl',
	components: {
		ToggleButton,
	},
	computed: {
		...mapState(useNodeDataInspectorStore, ['isShownInspectorPanel']),
		buttonStyle(): string
		{
			return AirButtonStyle.OUTLINE_ACCENT_2;
		},
		buttonText(): string
		{
			return this.isShownInspectorPanel
				? Loc.getMessage('BIZPROCDESIGNER_EDITOR_NODE_DATA_INSPECTOR_TOGGLE_BUTTON_HIDE')
				: Loc.getMessage('BIZPROCDESIGNER_EDITOR_NODE_DATA_INSPECTOR_TOGGLE_BUTTON_SHOW')
			;
		},
		buttonIcon(): string
		{
			return this.isShownInspectorPanel
				? Outline.CROSSED_EYE
				: Outline.OBSERVER
			;
		},
	},
	methods: {
		...mapActions(useNodeDataInspectorStore, ['toggleInspectorPanel']),
		toggleInspector(): void
		{
			this.toggleInspectorPanel();
		},
	},
	template: `
		<ToggleButton
			:style="buttonStyle"
			:text="buttonText"
			:leftIcon="buttonIcon"
			wide
			@click="toggleInspector"
		/>
	`,
};
