import { Type } from 'main.core';
import { defineStore } from 'ui.vue3.pinia';
import type { Block } from '../types';

type NodeDataInspectorStoreState = {
	block: Block | null,
	isShownInspectorPanel: boolean,
}

export const useNodeDataInspectorStore = defineStore('bizprocdesigner-node-data-inspector-store', {
	state: (): NodeDataInspectorStoreState => ({
		block: null,
		isShownInspectorPanel: false,
	}),
	actions: {
		setBlock(block: Block): void
		{
			this.block = block;
		},
		toggleInspectorPanel(shouldShow: ?boolean): void
		{
			if (Type.isBoolean(shouldShow))
			{
				this.isShownInspectorPanel = shouldShow;

				return;
			}

			this.isShownInspectorPanel = !this.isShownInspectorPanel;
		},
	},
});
